use std::env;
use std::fs;
use std::io::Read;
use std::process;

struct Args {
    path: String,
    has_header: bool,
    delimiter: u8,
}

fn parse_args() -> Result<Args, String> {
    let mut path: Option<String> = None;
    let mut has_header = false;
    let mut delimiter: u8 = b',';

    let mut it = env::args().skip(1);
    while let Some(arg) = it.next() {
        match arg.as_str() {
            "--has-header" => has_header = true,
            "--delimiter" => {
                let val = it
                    .next()
                    .ok_or_else(|| "--delimiter requires a value".to_string())?;
                let bytes = val.as_bytes();
                if bytes.len() != 1 {
                    return Err("--delimiter must be a single character".to_string());
                }
                delimiter = bytes[0];
            }
            other => {
                if path.is_some() {
                    return Err(format!("unexpected argument: {other}"));
                }
                path = Some(other.to_string());
            }
        }
    }

    if delimiter == b'"' {
        return Err("--delimiter cannot be the quote character".to_string());
    }

    let path = path.ok_or_else(|| {
        "usage: csv_row_counter <path> [--has-header] [--delimiter <c>]".to_string()
    })?;
    Ok(Args {
        path,
        has_header,
        delimiter,
    })
}

// Counts CSV rows honoring RFC4180 quoting: a quoted field ("...") may
// contain literal newlines, and "" inside a quoted field is an escaped quote.
fn count_rows(contents: &str) -> usize {
    let mut rows = 0usize;
    let mut in_quotes = false;
    let mut row_has_content = false;
    let mut chars = contents.chars().peekable();

    while let Some(c) = chars.next() {
        row_has_content = true;
        match c {
            '"' => {
                if in_quotes && chars.peek() == Some(&'"') {
                    chars.next();
                } else {
                    in_quotes = !in_quotes;
                }
            }
            '\n' if !in_quotes => {
                rows += 1;
                row_has_content = false;
            }
            '\r' if !in_quotes => {
                if chars.peek() != Some(&'\n') {
                    rows += 1;
                    row_has_content = false;
                }
            }
            _ => {}
        }
    }

    if row_has_content {
        rows += 1;
    }

    rows
}

fn run() -> Result<usize, String> {
    let args = parse_args()?;
    let _ = args.delimiter; // reserved for future field-level parsing

    let mut file = fs::File::open(&args.path)
        .map_err(|e| format!("failed to open {}: {}", args.path, e))?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)
        .map_err(|e| format!("failed to read {}: {}", args.path, e))?;

    let mut count = count_rows(&contents);
    if args.has_header && count > 0 {
        count -= 1;
    }
    Ok(count)
}

fn main() {
    match run() {
        Ok(count) => {
            println!("{count}");
            process::exit(0);
        }
        Err(e) => {
            eprintln!("error: {e}");
            process::exit(1);
        }
    }
}
