use std::env;
use std::fs;
use std::io;
use std::process;

/// Counts CSV rows in `content`, respecting RFC4180-style quoting so that
/// newlines embedded inside a quoted field don't count as row boundaries.
fn count_csv_rows(content: &str) -> usize {
    let mut count = 0usize;
    let mut in_quotes = false;
    let mut row_has_content = false;
    let mut chars = content.chars().peekable();

    while let Some(c) = chars.next() {
        row_has_content = true;
        match c {
            '"' => {
                if in_quotes {
                    if chars.peek() == Some(&'"') {
                        chars.next(); // escaped quote ("")
                    } else {
                        in_quotes = false;
                    }
                } else {
                    in_quotes = true;
                }
            }
            '\r' => {
                if !in_quotes {
                    if chars.peek() == Some(&'\n') {
                        chars.next();
                    }
                    count += 1;
                    row_has_content = false;
                }
            }
            '\n' => {
                if !in_quotes {
                    count += 1;
                    row_has_content = false;
                }
            }
            _ => {}
        }
    }

    if row_has_content {
        count += 1; // last row with no trailing newline
    }

    count
}

/// Reads `path` and returns the row count, optionally excluding the header row.
fn run(path: &str, exclude_header: bool) -> io::Result<usize> {
    let content = fs::read_to_string(path)?;
    let mut count = count_csv_rows(&content);
    if exclude_header && count > 0 {
        count -= 1;
    }
    Ok(count)
}

fn main() {
    let args: Vec<String> = env::args().collect();

    if args.len() < 2 {
        let prog = args.first().map(String::as_str).unwrap_or("csv_row_counter");
        eprintln!("Usage: {} <path-to-csv> [--no-header]", prog);
        process::exit(1);
    }

    let path = &args[1];
    let exclude_header = args.iter().skip(2).any(|a| a == "--no-header");

    match run(path, exclude_header) {
        Ok(count) => println!("{}", count),
        Err(e) => {
            eprintln!("error: could not read '{}': {}", path, e);
            process::exit(1);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Write;
    use std::sync::atomic::{AtomicUsize, Ordering};

    static COUNTER: AtomicUsize = AtomicUsize::new(0);

    fn write_temp_file(content: &str) -> std::path::PathBuf {
        let n = COUNTER.fetch_add(1, Ordering::SeqCst);
        let mut path = env::temp_dir();
        path.push(format!("csv_row_counter_test_{}_{}.csv", process::id(), n));
        let mut f = fs::File::create(&path).expect("create temp file");
        f.write_all(content.as_bytes()).expect("write temp file");
        path
    }

    #[test]
    fn normal_file_counts_all_rows_and_excludes_header() {
        let path = write_temp_file("a,b,c\n1,2,3\n4,5,6\n");
        let path_str = path.to_str().unwrap();

        assert_eq!(run(path_str, false).unwrap(), 3);
        assert_eq!(run(path_str, true).unwrap(), 2);

        fs::remove_file(path).unwrap();
    }

    #[test]
    fn empty_file_counts_zero() {
        let path = write_temp_file("");
        let path_str = path.to_str().unwrap();

        assert_eq!(run(path_str, false).unwrap(), 0);

        fs::remove_file(path).unwrap();
    }

    #[test]
    fn quoted_field_with_embedded_newline_is_one_row() {
        let path = write_temp_file("a,\"line1\nline2\",b\nc,d,e\n");
        let path_str = path.to_str().unwrap();

        assert_eq!(run(path_str, false).unwrap(), 2);

        fs::remove_file(path).unwrap();
    }

